PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE contacts (
      id           TEXT PRIMARY KEY,
      company_id   TEXT NOT NULL REFERENCES companies(id) ON DELETE CASCADE,
      name         TEXT NOT NULL,
      title        TEXT,
      email        TEXT,
      phone        TEXT,
      linkedin_url TEXT,
      source       TEXT,                 -- e.g. "website", "linkedin", "manual"
      verified     INTEGER NOT NULL DEFAULT 0,  -- 0 = unverified, 1 = verified
      created_at   TEXT NOT NULL DEFAULT (datetime('now'))
    , twitter_url TEXT, github_url TEXT, bio TEXT, tenure TEXT, email_pattern TEXT, email_confidence REAL DEFAULT 0, last_enriched_at DATETIME);
COMMIT;
